Edit 1 â€” FindingsLog: change
  `public final class FindingsLog: @unchecked Sendable {`
  to
  `public final class FindingsLog {`
  Nothing else. It is confined to the ValidationSession actor and needs no Sendable
  conformance; dropping it introduces no diagnostic (a non-Sendable class stored in actor
  state and never escaped is legal).

Edit 2 â€” IDBox: DELETE the nested `IDBox` class entirely. In `sleep(until:tolerance:)`,
  allocate the id up front and capture it as an immutable `let`:

    func sleep(until deadline: Instant, tolerance: Duration? = nil) async throws {
        try Task.checkCancellation()
        let id = lock.withLock { state -> Int in
            let next = state.nextID
            state.nextID += 1
            return next
        }
        try await withTaskCancellationHandler {
            try await withCheckedThrowingContinuation { (continuation: CheckedContinuation) in
                let resumeImmediately = lock.withLock { state -> Bool in
                    if deadline <= state.now { return true }
                    state.sleepers.append(Sleeper(id: id, deadline: deadline, continuation: continuation))
                    return false
                }
                if resumeImmediately { continuation.resume() }
            }
        } onCancel: {
            let cancelled: CheckedContinuation? = lock.withLock { state in
                guard let index = state.sleepers.firstIndex(where: { $0.id == id }) else { return nil }
                return state.sleepers.remove(at: index).continuation
            }
            cancelled?.resume(throwing: CancellationError())
        }
    }

  (`id` is now a Sendable `let Int` captured by both closures â€” no shared mutable box.)

Edit 3 â€” GatedFetcher: convert class -> actor; drop the lock.

    actor GatedFetcher: StreamFetching {
        private let inner: ScriptedStreamFetcher
        private let gateURL: URL
        private let gate: FetchGate
        private var hasGated = false

        init(inner: ScriptedStreamFetcher, gateURL: URL, gate: FetchGate) {
            self.inner = inner
            self.gateURL = gateURL
            self.gate = gate
        }

        func fetch(_ url: URL) async -> FetchResult {
            if url == gateURL, !hasGated {
                hasGated = true
                await gate.block()
            }
            return await inner.fetch(url)
        }
    }
